import React, { useState } from 'react';

function TradeForm(props) {
    const [stock, setStock] = useState('')
    const [method,setMethod] = useState('')
    const [quantity, setQuantity] = useState('')
    const [profitLoss, setProfitLoss] = useState('')


    const handleStock = e => {
        setStock(e.target.value)     
    }
    const handleMethod = e => {
        setMethod(e.target.value)
    }
    const handleQuantity = e => {
        setQuantity(e.target.value)
    }
    const handleProfitLoss = e => {
        setProfitLoss(e.target.value)
    }

    const handleSubmit = e => {
        e.preventDefault()
        const newTrade = [{
            stock:stock,
            method:method,
            quantity:quantity,
            profitLoss:profitLoss
        }]
        props.setTradeList([ ...props.tradeList,...newTrade ])
        console.log(props.tradeList)
    }

    return(
        <form onSubmit={handleSubmit}>
            <span>Stock</span><span className='buffer'></span>
            <span>Method</span><span className='buffer'></span>
            <span>Quantity</span><span className='buffer'></span>
            <span>P/L</span><span className='buffer'></span>

            <p className='formLabel-buffer'></p>

            <select value={stock} onChange={handleStock} autoFocus>
                <option>MES</option>
            </select>
            <select value={method} onChange={handleMethod}>
                <option>Bollinger</option>
                <option>--S & R--</option>
            </select >
            <input value={quantity} onChange={handleQuantity} type='number' min='1' step='1' />
            <input value={profitLoss} onChange={handleProfitLoss} type='number' step='0.25' />

            <button type='submit'>+Trade</button>
        </form>  
    )
}

export default TradeForm;
